// ---------------------------------------------------------------------------
// BitpackFixed — non-negative inputs only.
//
// Strategy: generate `Vec<u32>` values, then clamp each to fit within
// a randomly chosen bit width (1..=32).  This keeps all values in-domain.
// ---------------------------------------------------------------------------

#[test]
fn bitpack_fixed_roundtrip_arbitrary_u32() {
    arbtest(|u| {
        // Pick a bit width in [1, 32].
        let width = (u.arbitrary::<u8>()? % 32) + 1;
        let max_val: u32 = if width >= 32 {
            u32::MAX
        } else {
            (1u32 << width) - 1
        };
        // Clamp each element to [0, max_val] so they fit.
        let raw: Vec<u32> = u.arbitrary()?;
        let values: Vec<u32> = raw.into_iter().map(|v| v & max_val).collect();

        let pipeline = Pipeline::new(
            DataType::U32,
            vec![nb(BitpackFixed::new(DataType::U32, width as u32).unwrap())],
        )
        .unwrap();
        let encoded = pipeline.encode(ColumnData::U32(values.clone())).unwrap();
        let decoded = pipeline.decode(encoded).unwrap();
        assert_eq!(decoded, ColumnData::U32(values));
        Ok(())
    });
}

#[test]
fn bitpack_fixed_roundtrip_arbitrary_u64() {
    arbtest(|u| {
        // Pick a bit width in [1, 64].
        let width = (u.arbitrary::<u8>()? % 64) + 1;
        let max_val: u64 = if width >= 64 {
            u64::MAX
        } else {
            (1u64 << width) - 1
        };
        let raw: Vec<u64> = u.arbitrary()?;
        let values: Vec<u64> = raw.into_iter().map(|v| v & max_val).collect();

        let pipeline = Pipeline::new(
            DataType::U64,
            vec![nb(BitpackFixed::new(DataType::U64, width as u32).unwrap())],
        )
        .unwrap();
        let encoded = pipeline.encode(ColumnData::U64(values.clone())).unwrap();
        let decoded = pipeline.decode(encoded).unwrap();
        assert_eq!(decoded, ColumnData::U64(values));
        Ok(())
    });
}

