#[test]
fn pcodec_roundtrip_arbitrary_f64() {
    // Pcodec operates on raw float bits — NaN round-trips bitwise.
    arbtest(|u| {
        let bits: Vec<u64> = u.arbitrary()?;
        let values: Vec<f64> = bits.iter().map(|&b| f64::from_bits(b)).collect();

        let pipeline = Pipeline::new(
            DataType::F64,
            vec![blk(Pcodec::new(DataType::F64, None).unwrap())],
        )
        .unwrap();
        let encoded = pipeline.encode(ColumnData::F64(values.clone())).unwrap();
        let ColumnData::F64(decoded_vals) = pipeline.decode(encoded).unwrap() else {
            panic!("expected F64");
        };
        assert_eq!(decoded_vals.len(), values.len());
        for (orig, got) in values.iter().zip(decoded_vals.iter()) {
            assert_eq!(orig.to_bits(), got.to_bits());
        }
        Ok(())
    });
}

// ---------------------------------------------------------------------------
// Higher-level: round-trip through the top-level `compress` / `decompress`
// (HEC0) API for I64 and Bytes — exercises the whole default-pipeline path.
// ---------------------------------------------------------------------------

#[test]
fn hec0_compress_decompress_arbitrary_i64() {
    arbtest(|u| {
        let values: Vec<i64> = u.arbitrary()?;
        let data = ColumnData::I64(values.clone());
        let compressed = compress(data).unwrap();
        let recovered = decompress(&compressed).unwrap();
        assert_eq!(recovered, ColumnData::I64(values));
        Ok(())
    });
}

#[test]
fn hec0_compress_decompress_arbitrary_bytes() {
    arbtest(|u| {
        let bytes: Vec<u8> = u.arbitrary()?;
        let data = ColumnData::Bytes(bytes.clone());
        let compressed = compress(data).unwrap();
        let recovered = decompress(&compressed).unwrap();
        assert_eq!(recovered, ColumnData::Bytes(bytes));
        Ok(())
    });
}

#[test]
fn hec0_compress_decompress_arbitrary_f64() {
    arbtest(|u| {
        // Use bit-based construction so NaN is included.
        let bits: Vec<u64> = u.arbitrary()?;
        let values: Vec<f64> = bits.iter().map(|&b| f64::from_bits(b)).collect();
        let data = ColumnData::F64(values.clone());
        let compressed = compress(data).unwrap();
        let ColumnData::F64(recovered) = decompress(&compressed).unwrap() else {
            panic!("expected F64");
        };
        assert_eq!(recovered.len(), values.len());
        for (orig, got) in values.iter().zip(recovered.iter()) {
            assert_eq!(orig.to_bits(), got.to_bits());
        }
        Ok(())
    });
}
